function getExecutiveModeSummary() {
  const focus = getDailyFocusSummary();
  const focusProject = getDailyFocusProject();
  const activeLocalWorkProject = getActiveLocalWorkProject();
  const handoffPoint = getFirstManualImplementationHandoffPoint();
  const nextProject =
    activeLocalWorkProject ||
    (handoffPoint && state.projects.find((project) => project.id === handoffPoint.id)) ||
    focusProject ||
    getMorningProject();
  const openDecision = getOpenDecisionEntries()[0] || null;
  const workBriefStep = getNextWorkBriefManualStep();
  const nextManualStep = activeLocalWorkProject
    ? { nextManualStep: getNextManualStep(activeLocalWorkProject) }
    : handoffPoint || workBriefStep;

  return {
    focus,
    activeLocalWorkProject,
    nextProject,
    openDecision,
    workBriefStep,
    handoffPoint,
    nextManualStep,
  };
}

function executiveModeAction(action) {
  if (action.type === "project" && action.projectId) {
    return `<button class="executive-mode-button" type="button" data-open-project="${escapeHtml(action.projectId)}">${escapeHtml(action.label)}</button>`;
  }

  if (action.type === "view" && action.view) {
    return `<button class="executive-mode-button" type="button" data-view-jump="${escapeHtml(action.view)}">${escapeHtml(action.label)}</button>`;
  }

  return `<a class="executive-mode-button" href="${escapeHtml(action.href || "#analysis-details-title")}">${escapeHtml(action.label)}</a>`;
}

function getHrDailyAgentSuggestion() {
  const hrAgent = extendedLeadershipAgents.find((agent) => agent.name === "HR-/Team-Agent");
  const candidates = [...agents, ...extendedLeadershipAgents.filter((agent) => agent.name !== "HR-/Team-Agent")];
  const weightedCandidates = candidates.map((agent, index) => {
    const text = [
      agent.name,
      agent.mandate,
      agent.role,
      agent.core,
      agent.boundary,
      ...(agent.strengths || []),
      ...(agent.possibleUseAreas || []),
    ]
      .filter(Boolean)
      .join(" ");
    const needsBoundary = /Freigabe|Grenze|nicht|keine|Risiko|Datenschutz|Compliance|Claim|Zahlung|Deployment|Automationen/i.test(text);
    const canGainAutonomy = /planen|vorbereiten|strukturieren|dokumentieren|prüfen|Briefing|Matrix|Backlog|SOP/i.test(text);

    return {
      agent,
      score: (needsBoundary ? 2 : 0) + (canGainAutonomy ? 2 : 0) + ((index + new Date().getDate()) % 5),
    };
  });
  const target = weightedCandidates.sort((a, b) => b.score - a.score)[0]?.agent || agents[0];

  return {
    hrAgentName: hrAgent?.name || "HR-/Team-Agent",
    targetName: target.name,
    improvement:
      "1 % Verbesserung: Rolle, Grenze und nächstes Ausgabeformat für einen konkreten Tagesfall schärfen.",
    manualStep:
      "Jamal wählt einen kleinen Trainingspunkt aus und lässt HR nur einen read-only Verbesserungsvorschlag formulieren.",
    autonomy:
      "Mehr Spielraum empfohlen, wenn der Agent nur analysiert, strukturiert, dokumentiert oder Entwürfe vorbereitet.",
    risk:
      "Keine echte Ausführung: keine E-Mail, kein Deployment, keine Tool-Verbindung, keine Freigabe, keine externe Aktion.",
  };
}

