function getLocalProjectRegisterCockpit() {
  const projects = Array.isArray(state.projects) ? state.projects.filter((project) => !isVideoContentAgentProject(project)) : [];
  const statusGroups = projects.reduce((groups, project) => {
    const status = project.status || project.lifecycleStatus || "ohne Status";
    groups[status] = (groups[status] || 0) + 1;
    return groups;
  }, {});
  const openDecisions = projects.filter((project) => getProjectOpenDecisionText(project) !== "Keine offene Entscheidung dokumentiert.");
  const blockedProjects = projects.filter((project) => /block|risiko|unklar|wartet/i.test(`${project.status || ""} ${project.risk || ""} ${project.blocker || ""}`));
  const rows = projects.slice(0, 8).map((project) => ({
    id: project.id,
    title: project.title || project.name || "Unbenanntes lokales Projekt",
    area: project.area || project.businessArea || "Bereich offen",
    status: project.status || project.lifecycleStatus || "lokal sichtbar",
    priority: project.priority || project.leadershipConnection?.prioritaet || "nicht gesetzt",
    nextStep: getNextManualStep(project),
    decision: getProjectOpenDecisionText(project),
    agent: getProjectAgentRecommendation(project),
    connection: project.leadershipConnection?.status || "lokal",
  }));

  return {
    projects,
    rows,
    counts: {
      total: projects.length,
      openDecisions: openDecisions.length,
      blocked: blockedProjects.length,
      visibleRows: rows.length,
    },
    statusGroups,
    emptyState: [
      "Noch keine lokalen Projekte im Register sichtbar.",
      "Das Chef-Cockpit ist vorbereitet.",
      "Sobald lokale Projekte vorhanden sind, erscheinen sie hier als lokale Registeransicht.",
      "Es wird nichts automatisch nach Airtable übertragen.",
    ],
    rules: [
      "nur lokale Projektdaten aus der bestehenden App anzeigen",
      "keine Airtable-API aufrufen",
      "keine Projektdaten synchronisieren",
      "keine Daten importieren oder exportieren",
      "keine Schreib-, Änderungs-, Erstell- oder Löschaktion",
      "keine automatische Freigabe",
      "keine Tokens, Secrets oder echten Airtable-Daten anzeigen",
    ],
    focusQuestions: [
      "Welches Projekt braucht heute Aufmerksamkeit?",
      "Wo fehlt ein nächster manueller Schritt?",
      "Welche Entscheidung liegt bei Jamal?",
      "Welcher Agent oder Bereich könnte unterstützen?",
      "Welche Projekte bleiben nur lokal und dürfen nicht übertragen werden?",
    ],
  };
}

function getLocalProjectRegisterDailyFocus() {
  const projects = Array.isArray(state.projects) ? state.projects.filter((project) => !isVideoContentAgentProject(project)) : [];
  const activeProjects = projects.filter((project) => {
    const status = String(project.status || project.lifecycleStatus || "").toLowerCase();
    return !status.includes("abgeschlossen") && !status.includes("archiviert");
  });
  const hasUsefulNextStep = (project) => {
    const step = getNextManualStep(project);
    return step && !/nicht dokumentiert|muss geklärt|offen/i.test(step);
  };
  const hasOpenDecision = (project) => {
    const decision = getProjectOpenDecisionText(project);
    return decision && !/keine offene entscheidung/i.test(decision);
  };
  const scoreProject = (project) => {
    const priority = String(project.priority || project.leadershipConnection?.prioritaet || "").toLowerCase();
    const status = String(project.status || project.lifecycleStatus || "").toLowerCase();
    const privacy = String(project.privacyClass || project.datenschutzklasse || "").toLowerCase();
    let score = 0;
    if (priority.includes("kritisch") || priority === "a") score += 45;
    if (priority.includes("hoch") || priority === "b") score += 32;
    if (priority.includes("normal") || priority === "c") score += 18;
    if (hasOpenDecision(project)) score += 24;
    if (/block|wartet|entscheidung/i.test(status)) score += 18;
    if (hasUsefulNextStep(project)) score += 22;
    if (privacy.includes("gesperrt")) score -= 100;
    if (status.includes("abgeschlossen") || status.includes("archiviert")) score -= 100;
    return score;
  };
  const focusProject = activeProjects
    .map((project) => ({ project, score: scoreProject(project) }))
    .sort((a, b) => b.score - a.score)[0]?.project || null;
  const focusDecision = focusProject && hasOpenDecision(focusProject) ? getProjectOpenDecisionText(focusProject) : "";
  const recommendedAgent = getProjectAgentRecommendation(focusProject);

  return {
    project: focusProject,
    focus: focusProject
      ? {
          title: focusProject.title || focusProject.name || "Lokales Projekt",
          reason: hasOpenDecision(focusProject)
            ? "Dieses Projekt hat eine offene Entscheidung und sollte deshalb morgens sichtbar sein."
            : hasUsefulNextStep(focusProject)
              ? "Dieses Projekt hat einen klaren nächsten manuellen Schritt und eignet sich für Tagesfortschritt."
              : "Dieses Projekt braucht Klärung, bevor sinnvoll weitergearbeitet werden kann.",
          nextStep: getNextManualStep(focusProject),
          decision: focusDecision || "Aktuell keine lokale Entscheidung für den Tagesfokus vorbereitet.",
          risk: focusProject.risk || focusProject.blocker || "Kein lokaler Blocker sichtbar.",
          agent: recommendedAgent,
          timebox: "25 bis 45 Minuten manuelle Klärung, danach Ergebnis lokal dokumentieren.",
          notToday: "Keine externe Aktion, keine Airtable-Übertragung, keine Automatisierung und keine finale Freigabe.",
        }
      : null,
    decisionCard: focusProject && focusDecision
      ? {
          question: focusDecision,
          project: focusProject.title || focusProject.name || "Lokales Projekt",
          why: "Die Entscheidung bestimmt, ob der nächste manuelle Schritt sinnvoll fortgesetzt werden kann.",
          options: ["Heute klären", "zur Nachbearbeitung markieren", "bewusst vertagen"],
          risk: "Ohne Entscheidung bleibt der nächste Schritt unscharf oder blockiert.",
          nextStep: "Entscheidungsfrage lesen, auf einen Satz kürzen und manuell festlegen, ob heute entschieden wird.",
        }
      : null,
    agentHelp: {
      agent: recommendedAgent || "Morgenbriefing-Agent",
      why: focusProject
        ? "Der Agent passt als lokale Orientierung zum aktuellen Projektstand und nächsten manuellen Schritt."
        : "Der Morgenbriefing-Agent kann eine kurze Tageszusammenfassung vorbereiten, sobald lokale Projekte vorhanden sind.",
      allowed: [
        "Tagesstruktur vorbereiten",
        "nächsten manuellen Schritt sortieren",
        "Blocker und Entscheidung sichtbar machen",
        "lokale Zusammenfassung formulieren",
      ],
      forbidden: [
        "keinen Agenten automatisch starten",
        "keine externe Aktion auslösen",
        "keine Freigabe ersetzen",
        "keine Daten übertragen",
      ],
      manualAssignment: focusProject
        ? `Bitte bereite für ${focusProject.title || focusProject.name || "dieses Projekt"} den nächsten manuellen Schritt und die offene Entscheidung kurz vor.`
        : "Bitte bereite eine kurze lokale Tagesübersicht vor, sobald ein Projekt vorhanden ist.",
    },
    logic: [
      "Kritische oder hohe Priorität zuerst prüfen",
      "Projekte mit offener Entscheidung sichtbar machen",
      "Blockierte Projekte nur anzeigen, wenn Jamal etwas manuell lösen kann",
      "Projekte mit klarem nächsten Schritt bevorzugen",
      "Projekte ohne nächsten Schritt als Klärung nötig markieren",
      "Abgeschlossene oder archivierte Projekte nicht als Tagesfokus vorschlagen",
      "Projekte mit gesperrter Datenschutzklasse nicht für externe Anbindung vormerken",
      "Jamal behält die endgültige Entscheidung",
    ],
    actionSteps: [
      "Erstes Projekt öffnen",
      "Nächsten manuellen Schritt prüfen",
      "Offene Entscheidung klären",
      "Falls nötig passenden Agenten manuell beauftragen",
      "Am Abend Ergebnis im Projektverlauf dokumentieren",
    ],
    boundaries: [
      "Tagesfokus ist nur eine lokale Anzeige",
      "keine automatische Projektwahl",
      "keine externe Aktion",
      "keine Airtable-Nutzung",
      "keine Synchronisierung",
      "keine Benachrichtigung",
      "keine E-Mail",
      "kein Kalender",
      "kein Schreibzugriff",
      "Jamal entscheidet manuell",
    ],
    emptyState: [
      "Noch kein lokales Projekt für den Tagesfokus vorhanden.",
      "Das Tagesfokus-Modul ist vorbereitet.",
      "Sobald lokale Projekte vorhanden sind, kann daraus ein Fokusvorschlag angezeigt werden.",
      "Es wird nichts automatisch gestartet oder übertragen.",
    ],
    dummyExamples: [
      {
        project: "Demo-Projekt Tagesführung",
        reason: "hoher Nutzen für Chef-Cockpit",
        nextStep: "Fokuskarte prüfen",
        agent: "Morgenbriefing-Agent",
      },
      {
        project: "Demo-Projekt Entscheidung",
        reason: "offene Entscheidung blockiert nächsten Schritt",
        nextStep: "Entscheidungsfrage kürzen",
        agent: "Projektmanager-Agent",
      },
    ],
  };
}

function projectStatusText(project) {
  return String(project?.status || project?.lifecycleStatus || getProjectLifecycle(project || {}) || "").trim();
}

function isCompletedOrArchivedProject(project) {
  return /abgeschlossen|archiviert/i.test(projectStatusText(project));
}

function getRawProjectNextStep(project) {
  return (
    String(project?.nextManualStep || "").trim() ||
    (Array.isArray(project?.nextSteps) ? String(project.nextSteps.find((step) => String(step || "").trim()) || "").trim() : "") ||
    (Array.isArray(project?.sprint) ? String(project.sprint.find((step) => String(step || "").trim()) || "").trim() : "")
  );
}

function isUsefulRawNextStep(project) {
  const step = getRawProjectNextStep(project);
  return Boolean(step) && !/nicht dokumentiert|muss geklärt|offen|klären$/i.test(step);
}

function getStableOpenDecision(project) {
  const decision = getProjectOpenDecisionText(project);
  return /keine offene entscheidung|keine offene entscheidungsfrage/i.test(decision) ? "" : decision;
}

function shortenDayControlText(text, maxLength = 118) {
  const value = String(text || "").trim();
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength - 24).trim()} ... Details im Projekt prüfen`;
}

function getProjectPrivacyClass(project) {
  return String(project?.privacyClass || project?.datenschutzklasse || project?.dataPrivacyClass || "").trim().toLowerCase();
}

function hasBlockedProjectState(project) {
  return getProjectOpenBlockers(project).length > 0 || /blockiert|wartet auf entscheidung/i.test(projectStatusText(project));
}

function stableDayControlScore(project, index) {
  const priority = String(project.priority || project.leadershipConnection?.prioritaet || "").toLowerCase();
  const status = projectStatusText(project).toLowerCase();
  let score = 0;

  if (priority.includes("kritisch") || priority === "a") score += 700;
  if (priority.includes("hoch") || priority === "b") score += 600;
  if (getStableOpenDecision(project)) score += 500;
  if (hasBlockedProjectState(project)) score += 400;
  if (isUsefulRawNextStep(project)) score += 300;
  if (/aktiv|vorbereitet|planung|idee/i.test(status)) score += 200;

  return score - index / 1000;
}

function getStableDayControlAgent(project) {
  if (!project) return "Projektmanager-Agent";

  const text = [
    project.title,
    project.area,
    project.category,
    project.description,
    Array.isArray(project.tags) ? project.tags.join(" ") : "",
  ].join(" ");
  const privacy = getProjectPrivacyClass(project);
  const decision = getStableOpenDecision(project);
  const blocked = hasBlockedProjectState(project);

  if (decision) return /strategie|geschäft|freigabe|richtung/i.test(decision) ? "GF-Agent" : "Projektmanager-Agent";
  if (blocked || project.riskLevel === "Hoch" || /vertraulich|gesperrt/i.test(privacy)) return "Compliance-/Risiko-Agent";
  if (!isUsefulRawNextStep(project)) return "Projektmanager-Agent";
  if (!String(project.description || project.currentState || "").trim()) return "Wissens-/Archiv-Agent";
  if (/morgen|tagesführung|tagesfokus|briefing/i.test(text)) return "Morgenbriefing-Agent";
  if (/design|figma|web|ui|ux|landing|canva|bild|foto|video|heygen/i.test(text)) return "Design-Director-Agent";
  if (/content|text|post|artikel|präsentation|pitch/i.test(text)) return "Content-Agent";

  return "Projektmanager-Agent";
}

function getStableDayControlBar() {
  const projects = Array.isArray(state.projects) ? state.projects.filter((project) => !isVideoContentAgentProject(project)) : [];

  if (projects.length === 0) {
    return {
      version: "V6.3.8 Tagessteuerungsleiste lokal stabilisiert",
      status: "lokale Zustandslogik · keine Automatisierung · keine externe Aktion",
      hasProjects: false,
      focusProject: null,
      focus: "Noch kein lokales Projekt vorhanden",
      reason: "Die Tagessteuerung ist vorbereitet. Sobald lokale Projekte vorhanden sind, wird daraus ein Fokusvorschlag angezeigt.",
      nextStep: "Erstes Projekt lokal aufnehmen oder vorbereiten",
      decision: "Keine lokale Entscheidung vorhanden",
      agent: "Projektmanager-Agent",
      notToday: "Keine externe Integration starten",
      logicStatus: "lokal berechnet · nicht synchronisiert · nicht automatisiert",
    };
  }

  const eligibleProjects = projects.filter((project) => !isCompletedOrArchivedProject(project));
  const focusProject = eligibleProjects
    .map((project, index) => ({ project, score: stableDayControlScore(project, index) }))
    .sort((a, b) => b.score - a.score)[0]?.project || null;

  if (!focusProject) {
    return {
      version: "V6.3.8 Tagessteuerungsleiste lokal stabilisiert",
      status: "lokale Zustandslogik · keine Automatisierung · keine externe Aktion",
      hasProjects: true,
      focusProject: null,
      focus: "Kein aktives lokales Projekt vorhanden",
      reason: "Abgeschlossene oder archivierte Projekte werden nicht als Tagesfokus genutzt.",
      nextStep: "Aktives oder vorbereitetes Projekt lokal auswählen",
      decision: "Keine offene lokale Entscheidung",
      agent: "Projektmanager-Agent",
      notToday: "Keine externe Aktion aus abgeschlossenen oder archivierten Projekten ableiten",
      logicStatus: "lokal berechnet · nicht synchronisiert · nicht automatisiert",
    };
  }

  const blockers = getProjectOpenBlockers(focusProject);
  const status = projectStatusText(focusProject).toLowerCase();
  const privacy = getProjectPrivacyClass(focusProject);
  const rawNextStep = getRawProjectNextStep(focusProject);
  const decision = getStableOpenDecision(focusProject);
  const isBlocked = blockers.length > 0 || /blockiert/i.test(status);
  const isWaitingForDecision = /wartet auf entscheidung/i.test(status);
  const missingNextStep = !rawNextStep;
  const nextStep = isBlocked
    ? `Blocker zuerst manuell klären: ${blockers[0] || "Projektstatus ist blockiert."}`
    : missingNextStep
      ? "Nächsten manuellen Schritt klären"
      : rawNextStep;
  const decisionText = decision
    ? `${shortenDayControlText(decision)}${isWaitingForDecision || isBlocked ? " · als Blocker prüfen" : ""}`
    : "Keine offene lokale Entscheidung";
  const notToday = /gesperrt|vertraulich/i.test(privacy)
    ? "Nicht extern übertragen"
    : isBlocked
      ? "Nicht weiterbauen, bevor Blocker geklärt ist"
      : decision
        ? "Nicht umsetzen, bevor Jamal entschieden hat"
        : missingNextStep
          ? "Nicht mehrere Baustellen parallel öffnen"
          : "Keine externe Aktion ohne Freigabe";

  return {
    version: "V6.3.8 Tagessteuerungsleiste lokal stabilisiert",
    status: "lokale Zustandslogik · keine Automatisierung · keine externe Aktion",
    hasProjects: true,
    focusProject,
    focus: focusProject.title || focusProject.name || "Lokales Projekt",
    reason: decision
      ? "Dieses Projekt hat eine offene lokale Entscheidung."
      : isBlocked
        ? "Dieses Projekt zeigt einen Blocker, den Jamal manuell klären kann."
        : rawNextStep
          ? "Dieses Projekt hat einen klaren nächsten manuellen Schritt."
          : "Dieses Projekt braucht zuerst lokale Klärung.",
    nextStep,
    decision: decisionText,
    agent: getStableDayControlAgent(focusProject),
    notToday,
    logicStatus: "lokal berechnet · nicht synchronisiert · nicht automatisiert",
  };
}

