function getAgentAssignmentControl(manualAgentAssignment) {
  if (!manualAgentAssignment) {
    return {
      hasAssignment: false,
      status: "Nicht vorhanden",
      emptyState: [
        "Noch kein lokaler Agentenauftrag zur Kontrolle vorhanden.",
        "Die Kontrollansicht ist vorbereitet.",
        "Sobald die Tagessteuerung einen Agentenauftrag vorbereitet, kann Jamal ihn hier prüfen.",
        "Es wird nichts automatisch gestartet oder gesendet.",
      ],
    };
  }

  const combinedText = [
    manualAgentAssignment.agent,
    manualAgentAssignment.projectName,
    manualAgentAssignment.context,
    manualAgentAssignment.assignmentText,
    manualAgentAssignment.desiredResult,
    manualAgentAssignment.nextManualStep,
  ].join(" ");
  const hasSensitiveSignal = hasSensitiveProjectHistorySignal(combinedText);
  const hasBoundaries = manualAgentAssignment.forbidden?.some((item) => /keine externe|keine api|keine e-mail|keine daten|keine freigabe/i.test(item));
  const assignmentLength = String(manualAgentAssignment.assignmentText || "").length;
  const hasAgent = Boolean(String(manualAgentAssignment.agent || "").trim());
  const hasResult = Boolean(String(manualAgentAssignment.desiredResult || "").trim());
  const hasScope = Array.isArray(manualAgentAssignment.allowedScope) && manualAgentAssignment.allowedScope.length > 0;
  const status = hasSensitiveSignal
    ? "Nicht nutzen"
    : !hasBoundaries || !hasScope
      ? "Bereinigen"
      : assignmentLength > 520
        ? "Kürzen"
        : hasAgent && hasResult
          ? "Nutzbar"
          : "Prüfen";

  return {
    hasAssignment: true,
    status,
    clarity: assignmentLength > 520 ? "Prüfen" : hasAgent ? "Ja" : "Nein",
    scopeLimited: hasScope ? "Ja" : "Prüfen",
    boundariesIncluded: hasBoundaries ? "Ja" : "Prüfen",
    sensitiveExcluded: hasSensitiveSignal ? "Nein" : "Ja",
    resultClear: hasResult ? "Ja" : "Prüfen",
    summary: assignmentLength > 180 ? `${manualAgentAssignment.assignmentText.slice(0, 156).trim()} ... Details im Auftrag prüfen` : manualAgentAssignment.assignmentText,
  };
}

