function getCompactWorkModeOption(modeId = "start-today") {
  return compactWorkModeOptions.find((item) => item.id === modeId) || compactWorkModeOptions[0];
}

function compactWorkModeRecommendationMarkup(modeId = "start-today") {
  const mode = getCompactWorkModeOption(modeId);
  const airtableCopyText = airtableLocalReadOnlyConnection.copyText;
  return `
    <article class="airtable-pilot-rules">
      <h5>Klare Empfehlung</h5>
      <dl class="plugin-rollout-facts">
        <div><dt>Nächster manueller Schritt</dt><dd>${escapeHtml(mode.step)}</dd></div>
        <div><dt>Jetzt tun</dt><dd>${escapeHtml(mode.action)}</dd></div>
        <div><dt>Nicht nötig</dt><dd>${escapeHtml(mode.notNeeded)}</dd></div>
      </dl>
      <details class="local-agent-assignment-details">
        <summary>Warum empfiehlt die Zentrale das?</summary>
        <p>${escapeHtml(mode.why)} Passender Einstieg: ${escapeHtml(mode.v65)}.</p>
      </details>
    </article>
    ${projectManagerPluginTaskMarkup()}
    ${pluginWorkCapabilityMarkup("compact")}
    <article class="airtable-pilot-rules">
      <h5>V6.11.0 Erste echte lokale Airtable-Prüfung als Chef-Status</h5>
      <dl class="plugin-rollout-facts">
        <div><dt>Plugin</dt><dd>Airtable</dd></div>
        <div><dt>Ziel</dt><dd>lokale Minimalprüfung als einfachen Chef-Status zusammenfassen</dd></div>
        <div><dt>Version</dt><dd>V6.11.0</dd></div>
        <div><dt>Status</dt><dd>Airtable Chef-Status lokal zusammengefasst</dd></div>
        <div><dt>Freigabe</dt><dd>nur lokal über .env.local, nicht im Browser</dd></div>
        <div><dt>Airtable Status</dt><dd id="airtable-live-check-status">${escapeHtml(airtableLocalReadOnlyConnection.statusLine)}</dd></div>
        <div><dt>Hauptmeldung</dt><dd>${escapeHtml(airtableLocalReadOnlyConnection.meaning)}</dd></div>
        <div><dt>Nächster manueller Schritt</dt><dd>${escapeHtml(airtableLocalReadOnlyConnection.nextStep)}</dd></div>
        <div><dt>Grenze</dt><dd>Noch keine freie Datenanzeige</dd></div>
      </dl>
      <button class="secondary-button" type="button" data-airtable-live-check>Airtable Verbindung lokal prüfen</button>
      <article class="airtable-pilot-rules">
        <h5>Airtable Chef-Status</h5>
        <dl class="plugin-rollout-facts" id="airtable-chef-status-summary">
          <div><dt>Lokal erreichbar</dt><dd>noch nicht geprüft</dd></div>
          <div><dt>Minimalprüfung sicher abgeschlossen</dt><dd>nein</dd></div>
          <div><dt>Datenanzeige</dt><dd>weiterhin gesperrt</dd></div>
          <div><dt>Nächster sinnvoller Schritt</dt><dd>Zugangsdaten lokal ergänzen</dd></div>
        </dl>
      </article>
      <button class="secondary-button" type="button" data-airtable-first-preview>Chef-Status durch lokale Minimalprüfung aktualisieren</button>
      <p class="form-note" id="airtable-live-check-message">Airtable ist lokal noch nicht verbunden. Es fehlen lokale Zugangsdaten.</p>
      <div class="form-note" id="airtable-live-check-result">
        <strong>Status:</strong> nicht verbunden / Variablen fehlen / Verbindung erreichbar<br>
        <strong>Erklärung:</strong> Airtable ist lokal noch nicht verbunden. Es fehlen lokale Zugangsdaten.<br>
        <strong>Nächster Schritt:</strong> Zugangsdaten lokal in .env.local eintragen, Server neu starten und read-only Erreichbarkeit prüfen.<br>
        <strong>Grenze:</strong> Noch keine Datenanzeige, keine Schreibrechte, keine automatische Aktion.
      </div>
      <div class="form-note" id="airtable-first-preview-result">
        <strong>Status:</strong> Sicherheitsgrenze aktiv – keine Rohdaten angezeigt<br>
        <strong>Erklärung:</strong> Ohne Zugangsdaten und AIRTABLE_FIRST_READONLY_PREVIEW_APPROVED=true wird keine Airtable-Anfrage ausgeführt.<br>
        <strong>Grenze:</strong> Keine freie Datenanzeige, keine Feldwerte, keine echten Feldnamen.
      </div>
      <details class="local-agent-assignment-details">
        <summary>Minimalanzeige-Grenzen anzeigen</summary>
        <div class="airtable-pilot-bottom-grid">
          <article class="airtable-pilot-rules">
            <h5>Was diese Version erstmals vorbereitet</h5>
            ${list(airtableLocalReadOnlyConnection.preparedNow.map(escapeHtml))}
            <h5>Nur erlaubt, wenn Jamal manuell freigibt</h5>
            ${list(airtableLocalReadOnlyConnection.allowedWithApproval.map(escapeHtml))}
          </article>
          <article class="airtable-pilot-rules">
            <h5>Weiterhin gesperrt</h5>
            ${list(airtableLocalReadOnlyConnection.notAllowed.map(escapeHtml))}
          </article>
        </div>
      </details>
      <details class="local-agent-assignment-details">
        <summary>V6.9.0 Erste interne Übersicht read-only planen</summary>
        <div id="airtable-readonly-overview-planning">
          ${readOnlyOverviewPlanningMarkup("Noch nicht festlegen", false, "compact")}
        </div>
      </details>
      <details class="local-agent-assignment-details">
        <summary>V6.9.1 Feldsichtbarkeit und Anzeigegrenzen vorbereitet</summary>
        <div id="airtable-field-visibility-planning">
          ${fieldVisibilityPlanningMarkup("Noch nicht festlegen", false, "compact")}
        </div>
      </details>
      <details class="local-agent-assignment-details">
        <summary>V6.9.2 Freigabeansicht vor read-only Anzeige vorbereitet</summary>
        <div id="airtable-readonly-approval-view">
          ${readOnlyApprovalViewMarkup("Noch nicht festlegen", false, "compact")}
        </div>
      </details>
      <details class="local-agent-assignment-details">
        <summary>V6.9.3 Sichere read-only Vorschaugrenze vorbereitet</summary>
        <div id="airtable-readonly-preview-boundary">
          ${readOnlyPreviewBoundaryMarkup("Noch nicht festlegen", false, "compact")}
        </div>
      </details>
      <details class="local-agent-assignment-details">
        <summary>V6.9.4 V6.9.x Abschlusskontrolle vorbereitet</summary>
        <div id="airtable-v69-closure">
          ${v69ClosureMarkup(false, "compact")}
        </div>
      </details>
      <h5>Lokaler Kopiertext</h5>
      <pre class="local-agent-assignment-text" id="airtable-next-step-copytext">${escapeHtml(airtableCopyText)}</pre>
    </article>
  `;
}

function compactWorkModeMarkup() {
  const selectedMode = getCompactWorkModeOption();
  return `
    <section class="airtable-pilot-panel" id="v660-compact-work-mode" aria-labelledby="v660-compact-work-mode-title">
      <div class="airtable-pilot-status">
        <div>
          <p class="eyebrow">Heute wichtig</p>
          <h4 id="v660-compact-work-mode-title">Führen. Nicht suchen.</h4>
          <p>Wähle die Situation. Nimm den nächsten Schritt.</p>
        </div>
        <div class="plugin-rollout-status-badges">
          <span class="status-pill pending">lokal</span>
          <span class="status-pill pending">kompakt</span>
          <span class="status-pill blocked">keine Automatisierung</span>
        </div>
      </div>
      <p class="form-note">V6.7.1 · Chef-Modus als erster Bildschirm</p>
      <div class="airtable-pilot-bottom-grid">
        <article class="airtable-pilot-rules">
          <h5>Was mache ich jetzt?</h5>
          <label class="daily-focus-select" for="compact-work-mode-select">
            Aktuelle Arbeitssituation
            <select id="compact-work-mode-select">
              ${compactWorkModeOptions
                .map(
                  (item) =>
                    `<option value="${escapeHtml(item.id)}"${item.id === selectedMode.id ? " selected" : ""}>${escapeHtml(item.situation)}</option>`,
                )
                .join("")}
            </select>
          </label>
        </article>
        <div id="compact-work-mode-output">
          ${compactWorkModeRecommendationMarkup(selectedMode.id)}
        </div>
      </div>
    </section>
  `;
}

