function pluginWorkCapabilityMarkup(mode = "compact") {
  const first = pluginWorkCapabilityItems[0];
  const items = pluginWorkCapabilityItems;
  return `
    <article class="airtable-pilot-rules" id="v6120-plugin-work-capability">
      <h5>V6.12.0 Erste echte Plugin-Arbeitsfähigkeit für Agenten</h5>
      <dl class="plugin-rollout-facts">
        <div><dt>Status</dt><dd>Agenten werden plugin-arbeitsfähig vorbereitet</dd></div>
        <div><dt>Leitlinie</dt><dd>Weniger Verwaltung, mehr echte Systemleistung durch Agenten und Plugins</dd></div>
        <div><dt>Nächster arbeitsfähiger Agent</dt><dd>${escapeHtml(first.agent)}</dd></div>
        <div><dt>Passendes Plugin</dt><dd>${escapeHtml(first.plugin)}</dd></div>
        <div><dt>Erlaubte Aufgabe</dt><dd>${escapeHtml(first.task)}</dd></div>
        <div><dt>Erwartbares Ergebnis für Jamal</dt><dd>${escapeHtml(first.result)}</dd></div>
        <div><dt>Freigabegrenze</dt><dd>${escapeHtml(first.boundary)}</dd></div>
        <div><dt>Nächster manueller Schritt</dt><dd>${escapeHtml(first.nextStep)}</dd></div>
      </dl>
      <p class="form-note"><strong>Erster sinnvoller Plugin-Arbeitsschritt:</strong> Projektmanager-Agent mit Airtable read-only arbeitsfähig machen, damit aus dem Arbeitsgedächtnis Projektstand, Blocker und nächster Schritt abgeleitet werden können.</p>
      <p class="form-note"><strong>Warum das Jamal entlastet:</strong> Jamal muss nicht mehr selbst suchen, welcher Projektstand wichtig ist. Der Agent bereitet eine Chef-Zusammenfassung und den nächsten Schritt vor.</p>
      <details class="local-agent-assignment-details">
        <summary>Weitere Agent-Plugin-Zuordnungen anzeigen</summary>
        ${items
          .map(
            (item) => `
              <dl class="plugin-rollout-facts">
                <div><dt>Agent</dt><dd>${escapeHtml(item.agent)}</dd></div>
                <div><dt>Plugin</dt><dd>${escapeHtml(item.plugin)}</dd></div>
                <div><dt>Aufgabe</dt><dd>${escapeHtml(item.task)}</dd></div>
                <div><dt>Ergebnis</dt><dd>${escapeHtml(item.result)}</dd></div>
                <div><dt>Grenze</dt><dd>${escapeHtml(item.boundary)}</dd></div>
              </dl>
            `,
          )
          .join("")}
      </details>
    </article>
  `;
}

