function sanitizedChefOutputMarkup(output = projectManagerChefApproval.sanitizedOutputFallback) {
  return `
    <dl class="plugin-rollout-facts">
      <div><dt>Projektstand</dt><dd>${escapeHtml(output.projectStatus || projectManagerChefApproval.sanitizedOutputFallback.projectStatus)}</dd></div>
      <div><dt>Wichtigster Blocker</dt><dd>${escapeHtml(output.mainBlocker || projectManagerChefApproval.sanitizedOutputFallback.mainBlocker)}</dd></div>
      <div><dt>Nächster sinnvoller Schritt</dt><dd>${escapeHtml(output.nextMeaningfulStep || projectManagerChefApproval.sanitizedOutputFallback.nextMeaningfulStep)}</dd></div>
      <div><dt>Entscheidung für Jamal</dt><dd>${escapeHtml(output.decisionForJamal || projectManagerChefApproval.sanitizedOutputFallback.decisionForJamal)}</dd></div>
      <div><dt>Status der lokalen Ausführung</dt><dd>${escapeHtml(output.executionStatus || projectManagerChefApproval.sanitizedOutputFallback.executionStatus)}</dd></div>
    </dl>
  `;
}

function normalizeProjectManagerChefOutput(payload) {
  if (!payload) return projectManagerChefApproval.sanitizedOutputFallback;
  return {
    projectStatus: payload.projectStatus,
    mainBlocker: payload.mainBlocker,
    nextMeaningfulStep: payload.nextMeaningfulStep,
    decisionForJamal: payload.decisionForJamal,
    executionStatus: payload.executionStatus,
  };
}

function projectManagerChefApprovalResultMarkup(payload) {
  const status = payload?.chefApprovalStatus || "Freigegeben – sanitisierte Chef-Ausgabe vorbereitet";
  const nextStep = payload?.nextManualStep || "Lokale Voraussetzungen prüfen und Projektmanager-Auftrag freigeben.";
  const missingVariables = Array.isArray(payload?.missingVariables) && payload.missingVariables.length
    ? `<br><strong>Fehlt:</strong> ${escapeHtml(payload.missingVariables.join(", "))}`
    : "";

  return `
    <strong>Status:</strong> ${escapeHtml(status)}${missingVariables}<br>
    <strong>Nächster Schritt:</strong> ${escapeHtml(nextStep)}<br>
    <strong>Grenze:</strong> Keine Airtable-Rohdaten, keine Feldnamen, keine Feldwerte, keine Record-IDs, keine Tabellenstruktur, keine Schreibrechte, kein automatischer Agentenstart.
    <h5>Sanitisierte Chef-Ausgabe</h5>
    ${sanitizedChefOutputMarkup(payload?.sanitizedChefOutput)}
  `;
}

function projectManagerChefOutputResultMarkup(payload) {
  const missingVariables = Array.isArray(payload?.missingVariables) && payload.missingVariables.length
    ? `<br><strong>Fehlt:</strong> ${escapeHtml(payload.missingVariables.join(", "))}`
    : "";
  return `
    <strong>Status:</strong> ${escapeHtml(payload?.executionStatus || "Nicht erreichbar oder abgelehnt")}${missingVariables}<br>
    <strong>Grenze:</strong> Keine Airtable-Rohdaten, keine Feldnamen, keine Feldwerte, keine Record-IDs, keine Tabellenstruktur, keine Schreibrechte, kein automatischer Agentenstart.
    <h5>Erste sanitisierte Projektmanager-Ausgabe</h5>
    ${sanitizedChefOutputMarkup(normalizeProjectManagerChefOutput(payload))}
  `;
}

