function normalizeContentDesignUsableCanvaTask(payload) {
  const source = payload || knowledgeArchivePluginTask.fallback;
  const fallbackFormats = knowledgeArchivePluginTask.fallback.usableCanvaAvailableDesignFormats;
  const availableDesignFormats =
    Array.isArray(source.availableDesignFormats) && source.availableDesignFormats.length
      ? source.availableDesignFormats
      : fallbackFormats;
  const fallbackPromptVariants = knowledgeArchivePluginTask.fallback.usableCanvaFormatPromptVariants;
  const formatPromptVariants =
    source.formatPromptVariants && typeof source.formatPromptVariants === "object"
      ? { ...fallbackPromptVariants, ...source.formatPromptVariants }
      : fallbackPromptVariants;
  const selectedDesignFormat = availableDesignFormats.includes(source.selectedDesignFormat)
    ? source.selectedDesignFormat
    : knowledgeArchivePluginTask.fallback.usableCanvaSelectedDesignFormat;
  const selectedPrompt =
    formatPromptVariants[selectedDesignFormat] ||
    source.prefilledCanvaPrompt ||
    source.readyCanvaPrompt ||
    knowledgeArchivePluginTask.fallback.usableCanvaPrefilledPrompt;
  const designRequirements =
    Array.isArray(source.designRequirements) && source.designRequirements.length
      ? source.designRequirements.slice(0, 3)
      : knowledgeArchivePluginTask.fallback.usableCanvaRequirements;
  const mustNotHappen =
    Array.isArray(source.mustNotHappen) && source.mustNotHappen.length
      ? source.mustNotHappen.slice(0, 3)
      : knowledgeArchivePluginTask.fallback.usableCanvaMustNotHappen;
  return {
    source: source.source || knowledgeArchivePluginTask.fallback.usableCanvaTaskSource,
    projectContext: source.projectContext || knowledgeArchivePluginTask.fallback.usableCanvaProjectContext,
    purpose: source.purpose || knowledgeArchivePluginTask.fallback.usableCanvaPurpose,
    format: source.format || selectedDesignFormat || knowledgeArchivePluginTask.fallback.usableCanvaFormat,
    tone: source.tone || knowledgeArchivePluginTask.fallback.usableCanvaTone,
    availableDesignFormats,
    selectedDesignFormat,
    formatPromptVariants,
    recommendedDesignFormat:
      source.recommendedDesignFormat || knowledgeArchivePluginTask.fallback.usableCanvaRecommendedDesignFormat,
    recommendedDesignFormatLabel:
      source.recommendedDesignFormatLabel ||
      knowledgeArchivePluginTask.fallback.usableCanvaRecommendedDesignFormatLabel,
    recommendedDesignFormatReason:
      source.recommendedDesignFormatReason ||
      knowledgeArchivePluginTask.fallback.usableCanvaRecommendedDesignFormatReason,
    recommendedDesignFormatNextStep:
      source.recommendedDesignFormatNextStep ||
      knowledgeArchivePluginTask.fallback.usableCanvaRecommendedDesignFormatNextStep,
    mustAvoid:
      Array.isArray(source.mustAvoid) && source.mustAvoid.length
        ? source.mustAvoid.slice(0, 3)
        : knowledgeArchivePluginTask.fallback.usableCanvaMustAvoid,
    prefilledCanvaPrompt: selectedPrompt,
    readyCanvaPrompt:
      selectedPrompt || source.readyCanvaPrompt || source.copyTextForCanva || source.copyableCanvaTask || knowledgeArchivePluginTask.fallback.usableCanvaReadyPrompt,
    pasteIntoCanva:
      source.pasteIntoCanva || knowledgeArchivePluginTask.fallback.usableCanvaPasteIntoCanva,
    resultGoal:
      source.resultGoal || source.expectedResult || knowledgeArchivePluginTask.fallback.usableCanvaResultGoal,
    bestNextDesignStep:
      source.bestNextDesignStep || knowledgeArchivePluginTask.fallback.usableCanvaBestNextDesignStep,
    whyThisStepIsEnough:
      source.whyThisStepIsEnough || knowledgeArchivePluginTask.fallback.usableCanvaWhyStepEnough,
    oneMinuteAction:
      source.oneMinuteAction || knowledgeArchivePluginTask.fallback.usableCanvaOneMinuteAction,
    copyTextForCanva:
      selectedPrompt || source.copyTextForCanva || source.copyableCanvaTask || knowledgeArchivePluginTask.fallback.usableCanvaCopyTextForCanva,
    oneSentenceResult:
      source.oneSentenceResult || knowledgeArchivePluginTask.fallback.usableCanvaOneSentenceResult,
    doNow: source.doNow || knowledgeArchivePluginTask.fallback.usableCanvaDoNow,
    notAutomaticallyTriggered:
      source.notAutomaticallyTriggered || knowledgeArchivePluginTask.fallback.usableCanvaNotTriggered,
    designGoal: source.designGoal || knowledgeArchivePluginTask.fallback.usableCanvaDesignGoal,
    targetAudienceAndUseCase:
      source.targetAudienceAndUseCase || knowledgeArchivePluginTask.fallback.usableCanvaAudienceAndUse,
    formatOrPlacement: source.formatOrPlacement || selectedDesignFormat || knowledgeArchivePluginTask.fallback.usableCanvaFormat,
    designRequirements,
    mustNotHappen,
    expectedResult: source.expectedResult || knowledgeArchivePluginTask.fallback.usableCanvaExpectedResult,
    copyableCanvaTask: selectedPrompt || source.copyableCanvaTask || knowledgeArchivePluginTask.fallback.usableCanvaCopyText,
    nextManualStep: source.nextManualStep || knowledgeArchivePluginTask.fallback.usableCanvaNextStep,
    boundary: source.boundary || knowledgeArchivePluginTask.fallback.usableCanvaBoundary,
  };
}

