function renderProductiveWorkResultBlock(productiveManualHealthDayWork) {
  const result = productiveManualHealthDayWork?.result;
  if (!result) {
    return `<p class="form-note">Kein Ergebnis verfügbar.</p>`;
  }

  const analysis = result.analysis || productiveManualHealthDayWork.analysis;
  const detectedKeywords = Array.isArray(result.detectedKeywords)
    ? result.detectedKeywords
    : analysis?.detectedKeywords || [];
  const missingInputs = Array.isArray(result.missingInputs)
    ? result.missingInputs
    : analysis?.missingInputs || [];

  return `
    <dl class="plugin-rollout-facts">
      <div><dt>Produktivauftrag</dt><dd>${escapeHtml(productiveManualHealthDayWork.workRequest || "—")}</dd></div>
      <div><dt>Ergebnisquelle</dt><dd>${escapeHtml(productiveManualHealthDayWork.resultSource || "default")}</dd></div>
      <div><dt>Eingabekorridor</dt><dd>${escapeHtml(productiveManualHealthDayWork.productiveInputCorridorVersion || "—")}</dd></div>
      <div><dt>Auswertungskern</dt><dd>${escapeHtml(productiveManualHealthDayWork.productiveResultEngineVersion || result.productiveResultEngineVersion || "—")}</dd></div>
      <div><dt>Intent</dt><dd>${escapeHtml(result.intent || analysis?.intentLabel || "—")}</dd></div>
      <div><dt>Kategorie</dt><dd>${escapeHtml(result.category || analysis?.category || "—")}</dd></div>
      <div><dt>Priorität</dt><dd>${escapeHtml(result.priority || analysis?.priority || "—")}</dd></div>
      <div><dt>Komplexität</dt><dd>${escapeHtml(result.complexity || analysis?.complexity || "—")}</dd></div>
      <div><dt>Empfohlener Modus</dt><dd>${escapeHtml(result.recommendedMode || analysis?.recommendedMode || "—")}</dd></div>
      <div><dt>Erkannte Schlüsselwörter</dt><dd>${detectedKeywords.length ? detectedKeywords.map((item) => escapeHtml(item)).join(", ") : "—"}</dd></div>
      <div><dt>Fehlende Eingaben</dt><dd>${missingInputs.length ? missingInputs.map((item) => escapeHtml(item)).join("<br>") : "—"}</dd></div>
      <div><dt>Aus Auftrag abgeleitet</dt><dd>${result.derivedFromWorkRequest ? "ja" : "nein"}</dd></div>
      <div><dt>Auftragsvorschau</dt><dd>${escapeHtml(result.workRequestPreview || "—")}</dd></div>
      <div><dt>Zusammenfassung</dt><dd>${escapeHtml(result.summary)}</dd></div>
      <div><dt>Entscheidungen</dt><dd>${result.decisions.map((item) => escapeHtml(item)).join("<br>")}</dd></div>
      <div><dt>Nächste Aktionen</dt><dd>${result.nextActions.map((item) => escapeHtml(item)).join("<br>")}</dd></div>
      <div><dt>Risiken</dt><dd>${result.risks.map((item) => escapeHtml(item)).join("<br>")}</dd></div>
      <div><dt>Offene Punkte</dt><dd>${result.openPoints.map((item) => escapeHtml(item)).join("<br>")}</dd></div>
      <div><dt>Sicherheitszustand</dt><dd>${escapeHtml(result.safetyState)}</dd></div>
    </dl>
  `;
}

