function renderProductiveProjectSelectOptions(selectedProjectId) {
  const noneSelected = !selectedProjectId ? " selected" : "";
  const options = PRODUCTIVE_PROJECT_REGISTRY.map((project) => {
    const selected = project.id === selectedProjectId ? " selected" : "";
    return `<option value="${escapeHtml(project.id)}"${selected}>${escapeHtml(project.name)}</option>`;
  }).join("");
  return `<option value=""${noneSelected}>Kein Projekt / allgemeiner Auftrag</option>${options}`;
}

