function updateReadOnlyOverviewPlanning(selection = "Noch nicht festlegen", planned = false) {
  const safeSelection = airtableRegisterOverviewOptions.includes(selection) ? selection : "Noch nicht festlegen";
  const compactTarget = byId("airtable-readonly-overview-planning");
  const detailsTarget = byId("airtable-readonly-overview-planning-details");
  const v690TargetOverview = byId("airtable-v690-target-overview");
  if (compactTarget) compactTarget.innerHTML = readOnlyOverviewPlanningMarkup(safeSelection, planned, "compact");
  if (detailsTarget) detailsTarget.innerHTML = readOnlyOverviewPlanningMarkup(safeSelection, planned, "details");
  if (v690TargetOverview) v690TargetOverview.textContent = safeSelection;
  updateFieldVisibilityPlanning(safeSelection, false);
}

function updateFieldVisibilityPlanning(selection = "Noch nicht festlegen", prepared = false) {
  const safeSelection = airtableRegisterOverviewOptions.includes(selection) ? selection : "Noch nicht festlegen";
  const compactTarget = byId("airtable-field-visibility-planning");
  const detailsTarget = byId("airtable-field-visibility-planning-details");
  if (compactTarget) compactTarget.innerHTML = fieldVisibilityPlanningMarkup(safeSelection, prepared, "compact");
  if (detailsTarget) detailsTarget.innerHTML = fieldVisibilityPlanningMarkup(safeSelection, prepared, "details");
  updateReadOnlyApprovalView(safeSelection, false);
}

function updateReadOnlyApprovalView(selection = "Noch nicht festlegen", prepared = false) {
  const safeSelection = airtableRegisterOverviewOptions.includes(selection) ? selection : "Noch nicht festlegen";
  const compactTarget = byId("airtable-readonly-approval-view");
  const detailsTarget = byId("airtable-readonly-approval-view-details");
  if (compactTarget) compactTarget.innerHTML = readOnlyApprovalViewMarkup(safeSelection, prepared, "compact");
  if (detailsTarget) detailsTarget.innerHTML = readOnlyApprovalViewMarkup(safeSelection, prepared, "details");
  updateReadOnlyPreviewBoundary(safeSelection, false);
}

function updateReadOnlyPreviewBoundary(selection = "Noch nicht festlegen", prepared = false) {
  const safeSelection = airtableRegisterOverviewOptions.includes(selection) ? selection : "Noch nicht festlegen";
  const compactTarget = byId("airtable-readonly-preview-boundary");
  const detailsTarget = byId("airtable-readonly-preview-boundary-details");
  if (compactTarget) compactTarget.innerHTML = readOnlyPreviewBoundaryMarkup(safeSelection, prepared, "compact");
  if (detailsTarget) detailsTarget.innerHTML = readOnlyPreviewBoundaryMarkup(safeSelection, prepared, "details");
}

