function hasSensitiveProjectHistorySignal(text) {
  return /token|secret|passwort|password|private e-mail|private email|bankdaten|steuer|gesundheit|kundendaten|ausweis|vertrag|iban|api[-_\s]?key/i.test(
    String(text || ""),
  );
}

function getManualProjectHistoryTransferPreview() {
  const link = getLocalDayProjectHistoryLink();
  const project = link.project;
  const preview = link.preview;

  if (!project || !preview) {
    return {
      project: null,
      preview: null,
      canTransfer: false,
      reason: "Noch keine lokale Übernahme möglich. Erst Projekt und Tagesverlauf prüfen.",
      description: "",
      transferKey: "",
    };
  }

  const description = [
    "Quelle: Tagesverlauf V6.3.4",
    `Projekt: ${preview.project}`,
    `Kurzfassung: ${preview.dailyFocus}`,
    `Heute vorbereitet: ${preview.preparedToday}`,
    `Offen geblieben: ${preview.open}`,
    `Offene Entscheidung: ${preview.decision}`,
    `Blocker/Risiko: ${preview.blocker}`,
    `Empfohlener Agent: ${preview.agent}`,
    `Morgen zuerst: ${preview.tomorrowFirst}`,
    `Jamals Notiz: ${preview.jamalNote}`,
    "Hinweis: lokal übernommen, keine externe Aktion",
  ].join("\n");
  const transferKey = `${todayIso()}::v6.3.4::${project.id}`;
  const alreadyTransferred = project.lastDayHistoryTransferKey === transferKey;
  const sensitiveSignal = hasSensitiveProjectHistorySignal(description);

  return {
    project,
    preview,
    canTransfer: !alreadyTransferred && !sensitiveSignal,
    reason: alreadyTransferred
      ? "Dieser Tagesverlauf wurde bereits lokal übernommen."
      : sensitiveSignal
        ? "Übernahmefunktion vorbereitet, aber wegen möglicher sensibler Inhalte nicht aktiv."
        : "Eintrag kann nach Jamals Bestätigung lokal übernommen werden.",
    description,
    transferKey,
  };
}

function parseManualProjectHistoryLine(description, label) {
  const line = String(description || "")
    .split("\n")
    .find((item) => item.trim().startsWith(`${label}:`));
  return line ? line.replace(`${label}:`, "").trim() : "Nicht im lokalen Eintrag angegeben.";
}

function getProjectHistoryControlView() {
  const transferredEntries = state.projects
    .flatMap((project) =>
      getProjectHistory(project)
        .filter((entry) => String(entry.description || "").includes("Quelle: Tagesverlauf V6.3.4"))
        .map((entry) => ({ project, entry })),
    )
    .sort((a, b) => new Date(b.entry.at || 0).getTime() - new Date(a.entry.at || 0).getTime());
  const latest = transferredEntries[0] || null;

  if (!latest) {
    return {
      hasEntry: false,
      project: null,
      entry: null,
      fields: null,
      status: "Noch nicht übernommen",
      duplicateStatus: "Kein übernommener V6.3.4-Eintrag gefunden.",
      emptyState: [
        "Noch kein lokal übernommener Projektverlaufseintrag vorhanden.",
        "Die Kontrollansicht ist vorbereitet.",
        "Sobald ein echter lokaler Verlaufseintrag übernommen wurde, kann Jamal ihn hier prüfen.",
        "Es wird nichts automatisch geändert.",
      ],
    };
  }

  const description = latest.entry.description || "";
  const hasSensitiveSignal = hasSensitiveProjectHistorySignal(description);
  const duplicateCount = transferredEntries.filter(
    (item) => item.project.id === latest.project.id && item.entry.description === latest.entry.description,
  ).length;
  const status = hasSensitiveSignal
    ? "Bereinigen"
    : duplicateCount > 1
      ? "Löschen erwägen"
      : description.length > 900
        ? "Prüfen"
        : "Korrekt";

  return {
    hasEntry: true,
    project: latest.project,
    entry: latest.entry,
    fields: {
      project: latest.project.title || "Unbenanntes Projekt",
      at: formatHistoryDate(latest.entry.at),
      source: parseManualProjectHistoryLine(description, "Quelle"),
      summary: parseManualProjectHistoryLine(description, "Kurzfassung"),
      preparedToday: parseManualProjectHistoryLine(description, "Heute vorbereitet"),
      open: parseManualProjectHistoryLine(description, "Offen geblieben"),
      decision: parseManualProjectHistoryLine(description, "Offene Entscheidung"),
      blocker: parseManualProjectHistoryLine(description, "Blocker/Risiko"),
      agent: parseManualProjectHistoryLine(description, "Empfohlener Agent"),
      tomorrowFirst: parseManualProjectHistoryLine(description, "Morgen zuerst"),
      jamalNote: parseManualProjectHistoryLine(description, "Jamals Notiz"),
      transferStatus: "Lokal übernommen",
      duplicateStatus: duplicateCount > 1 ? "Mögliches Duplikat lokal prüfen." : "Duplikat-Schutz aktiv, kein identischer Mehrfacheintrag erkannt.",
      externalAction: "nein",
    },
    status,
    duplicateStatus: duplicateCount > 1 ? "Mögliches Duplikat lokal prüfen." : "Duplikat-Schutz aktiv, kein identischer Mehrfacheintrag erkannt.",
  };
}

function getMorningBriefingFromProjectHistory() {
  const historyItems = state.projects
    .flatMap((project) =>
      getProjectHistory(project).map((entry) => ({
        project,
        entry,
        timestamp: new Date(entry.at || 0).getTime(),
      })),
    )
    .sort((a, b) => b.timestamp - a.timestamp);
  const latest = historyItems[0] || null;

  if (!latest) {
    return {
      hasBriefing: false,
      focusProject: null,
      fields: null,
      emptyState: [
        "Noch kein lokaler Projektverlauf für ein Morgenbriefing vorhanden.",
        "Das Morgenbriefing-Modul ist vorbereitet.",
        "Sobald lokale Verlaufseinträge vorhanden sind, kann daraus ein vorsichtiger Morgenfokus angezeigt werden.",
        "Es wird nichts automatisch gestartet, übertragen oder entschieden.",
      ],
    };
  }

  const description = latest.entry.description || historyDescriptionFallback;
  const isTransferredDayHistory = description.includes("Quelle: Tagesverlauf V6.3.4");
  const summary = isTransferredDayHistory ? parseManualProjectHistoryLine(description, "Kurzfassung") : description;
  const open = isTransferredDayHistory ? parseManualProjectHistoryLine(description, "Offen geblieben") : getProjectOpenDecisionText(latest.project);
  const decision = isTransferredDayHistory ? parseManualProjectHistoryLine(description, "Offene Entscheidung") : getProjectOpenDecisionText(latest.project);
  const blocker = isTransferredDayHistory ? parseManualProjectHistoryLine(description, "Blocker/Risiko") : getProjectOpenBlockers(latest.project)[0] || "Kein lokaler Blocker im Verlauf erkannt.";
  const agent = isTransferredDayHistory ? parseManualProjectHistoryLine(description, "Empfohlener Agent") : getProjectAgentRecommendation(latest.project);
  const firstStep = isTransferredDayHistory ? parseManualProjectHistoryLine(description, "Morgen zuerst") : getNextManualStep(latest.project);
  const sensitiveSignal = hasSensitiveProjectHistorySignal(description);

  return {
    hasBriefing: true,
    focusProject: latest.project,
    latestEntry: latest.entry,
    fields: {
      project: latest.project.title || "Unbenanntes Projekt",
      lastEntryAt: formatHistoryDate(latest.entry.at),
      lastEntryType: latest.entry.type || "Notiz",
      summary,
      open,
      decision,
      blocker,
      agent,
      firstStep,
      briefingStatus: sensitiveSignal ? "Prüfen und bereinigen" : "lokal vorbereitet",
      notAllowed: "Keine automatische Projektänderung, keine Airtable-Nutzung, keine externe Aktion.",
    },
  };
}

