function renderMetrics() {
  const projects = state.projects;
  const activeProjects = projects.length;
  const blockedProjects = projects.filter((project) => getProjectOpenBlockers(project).length > 0).length;
  const projectsInApproval = projects.filter((project) => getProjectLifecycle(project) === "Freigabe").length;
  const openTickets = (state.tickets || []).filter((ticket) => ticket.status !== "Gelöst").length;
  const existingAgents = agents.length;

  const metrics = [
    { label: "Aktive Projekte", value: activeProjects, hint: "lokal sichtbare Projektakten" },
    { label: "Blockierte Projekte", value: blockedProjects, hint: "mit offenen Qualitäts- oder Supportblockern" },
    { label: "Projekte in Freigabe", value: projectsInApproval, hint: "Statuswert Freigabe, ohne automatische Entscheidung" },
    { label: "Offene Supportfälle", value: openTickets, hint: "nicht gelöste lokale Meldungen" },
    { label: "Vorhandene Agenten", value: existingAgents, hint: "angelegte Rollen, keine Ausführung" },
  ];

  byId("metric-grid").innerHTML = metrics
    .map(
      (metric) => `
        <article class="metric-tile">
          <p class="eyebrow">${metric.label}</p>
          <strong>${metric.value}</strong>
          <span>${metric.hint}</span>
        </article>
      `,
    )
    .join("");
}

function renderDailyFocus() {
  const focus = getDailyFocusSummary();
  const selectedProject = getDailyFocusProject();
  const selectedId = selectedProject?.id || "";
  const selectedReason = selectedProject ? getDailyFocusReason(selectedProject) : "";
  const selectedQuestion = selectedProject ? getDailyFocusQuestion(selectedProject) : "";
  const selectedTemplate = getDailyFocusDecisionTemplate(selectedProject);
  const selectedDecisionStatus = selectedProject ? getDailyFocusDecisionStatus(selectedProject) : "";
  const projectOptions = [
    `<option value="">Kein manueller Tagesfokus</option>`,
    ...state.projects.map(
      (project) =>
        `<option value="${escapeHtml(project.id)}" ${project.id === selectedId ? "selected" : ""}>${escapeHtml(project.title || "Unbenanntes Projekt")}</option>`,
    ),
  ].join("");

  byId("daily-focus-output").innerHTML = `
    <div class="daily-focus-top">
      <div>
        <span class="tag lifecycle-tag">Aktuelles Fokusprojekt</span>
        <h4>${escapeHtml(focus.projectName)}</h4>
        <p>${escapeHtml(focus.projectHint)}</p>
      </div>
      <label class="daily-focus-select">
        Fokusprojekt auswählen
        <select id="daily-focus-select" aria-label="Tagesfokus auswählen">
          ${projectOptions}
        </select>
      </label>
    </div>
    <form class="daily-focus-reason-form" data-daily-focus-reason-form>
      <label>
        Warum ist dieses Projekt heute der Fokus?
        <textarea id="daily-focus-reason" name="reason" rows="3" placeholder="Kurzer manueller Grund, zum Beispiel: Erst den wichtigsten Blocker klären." ${selectedId ? "" : "disabled"}>${escapeHtml(selectedReason)}</textarea>
      </label>
      <label>
        Welche Entscheidung ist heute offen?
        <textarea id="daily-focus-question" name="question" rows="3" placeholder="Zum Beispiel: Darf der nächste Test vorbereitet werden?" ${selectedId ? "" : "disabled"}>${escapeHtml(selectedQuestion)}</textarea>
      </label>
      <div class="decision-template-fields">
        <p class="form-subtitle">Entscheidungsvorlage</p>
        <label>
          Entscheidungsstatus
          <select id="daily-focus-decision-status" name="decisionStatus" ${selectedId ? "" : "disabled"}>
            <option value="" ${selectedDecisionStatus ? "" : "selected"}>Kein Entscheidungsstatus</option>
            <option value="offen" ${selectedDecisionStatus === "offen" ? "selected" : ""}>offen</option>
            <option value="vorbereitet" ${selectedDecisionStatus === "vorbereitet" ? "selected" : ""}>vorbereitet</option>
            <option value="entschieden" ${selectedDecisionStatus === "entschieden" ? "selected" : ""}>entschieden</option>
          </select>
        </label>
        <label>
          Optionen
          <textarea id="daily-focus-options" name="options" rows="3" placeholder="Welche Wege stehen zur Auswahl?" ${selectedId ? "" : "disabled"}>${escapeHtml(selectedTemplate.options)}</textarea>
        </label>
        <label>
          Empfehlung
          <textarea id="daily-focus-recommendation" name="recommendation" rows="3" placeholder="Welche Richtung wirkt aktuell am sinnvollsten?" ${selectedId ? "" : "disabled"}>${escapeHtml(selectedTemplate.recommendation)}</textarea>
        </label>
        <label>
          Risiko
          <textarea id="daily-focus-template-risk" name="templateRisk" rows="3" placeholder="Was kann schiefgehen oder muss geprüft werden?" ${selectedId ? "" : "disabled"}>${escapeHtml(selectedTemplate.risk)}</textarea>
        </label>
        <label>
          Jamals Entscheidung
          <textarea id="daily-focus-jamal-decision" name="jamalDecision" rows="3" placeholder="Noch offen oder kurze Entscheidung dokumentieren." ${selectedId ? "" : "disabled"}>${escapeHtml(selectedTemplate.jamalDecision)}</textarea>
        </label>
      </div>
      <div class="button-row">
        <button class="primary-button" type="submit" ${selectedId ? "" : "disabled"}>Tagesfokus-Hinweise speichern</button>
        <button class="secondary-button" type="button" data-document-focus-decision ${selectedId ? "" : "disabled"}>Entscheidung in Projektverlauf dokumentieren</button>
      </div>
      <p class="form-note">Manueller Hinweis von Jamal. Keine Freigabe, keine Aktion, kein Versand.</p>
    </form>
    <div class="briefing-list daily-focus-list">
      <article class="briefing-item">
        <span>1. Aktuelles Fokusprojekt</span>
        <strong>${escapeHtml(focus.projectName)}</strong>
      </article>
      <article class="briefing-item">
        <span>2. Warum heute Priorität?</span>
        <strong>${escapeHtml(focus.reason)}</strong>
      </article>
      <article class="briefing-item">
        <span>3. Kleinster nächster Schritt</span>
        <strong>${escapeHtml(focus.nextStep)}</strong>
      </article>
      <article class="briefing-item">
        <span>4. Welche Entscheidung ist heute offen?</span>
        <strong>${escapeHtml(focus.question)}</strong>
      </article>
      <article class="briefing-item">
        <span>5. Darf heute bewusst nicht passieren</span>
        <strong>${escapeHtml(focus.notAllowed)}</strong>
      </article>
    </div>
    ${renderDecisionTemplate(focus.decisionTemplate)}
    <p class="form-note">Diese Auswahl bleibt nur lokal im Browser. Sie löst keine Freigabe, keine Agentenaktion und keine externe Aktion aus.</p>
  `;
}

function renderDecisionTemplate(template) {
  if (!template.hasContent) {
    return `
      <section class="decision-template-card">
        <h4>Entscheidungsvorlage</h4>
        <div class="decision-status-line">
          <span>Entscheidungsstatus</span>
          <strong class="status-pill ${template.statusClass}">${escapeHtml(template.statusText)}</strong>
        </div>
        <p>${escapeHtml(template.fallback)}</p>
      </section>
    `;
  }

  return `
    <section class="decision-template-card">
      <h4>Entscheidungsvorlage</h4>
      <div class="decision-status-line">
        <span>Entscheidungsstatus</span>
        <strong class="status-pill ${template.statusClass}">${escapeHtml(template.statusText)}</strong>
      </div>
      <div class="decision-template-grid">
        <article>
          <span>Optionen</span>
          <strong>${escapeHtml(template.options)}</strong>
        </article>
        <article>
          <span>Empfehlung</span>
          <strong>${escapeHtml(template.recommendation)}</strong>
        </article>
        <article>
          <span>Risiko</span>
          <strong>${escapeHtml(template.risk)}</strong>
        </article>
        <article>
          <span>Jamals Entscheidung</span>
          <strong>${escapeHtml(template.jamalDecision)}</strong>
        </article>
      </div>
      <p class="form-note">Lokale Vorlage. Keine Freigabe, keine Aktion, keine Agentenausführung.</p>
    </section>
  `;
}

