function getMarketPluginProjectObservationFields(project) {
  const projectText = [
    project.title,
    project.area,
    project.description,
    project.targetGroup,
    project.value,
    project.model,
    project.status,
    project.lifecycleStatus,
    project.riskLevel,
    ...(project.risks || []),
    ...(project.dataNeeds || []),
    ...(project.compliance || []),
    ...(project.nextSteps || []),
  ]
    .join(" ")
    .toLowerCase();
  const fields = new Set();
  const has = (terms) => terms.some((term) => projectText.includes(term));

  if (has(["ki", "agent", "automation", "automatisierung", "plattform", "app", "mvp"])) {
    fields.add("KI-Tools");
  }
  if (has(["plugin", "integration", "api", "plattform", "tool", "system", "verbindung"])) {
    fields.add("Plugins");
  }
  if (has(["design", "bild", "video", "präsentation", "content", "marke", "lernprodukt", "dialog"])) {
    fields.add("Design");
  }
  if (has(["support", "inbox", "kunden", "kommunikation", "feedback", "partnerfragen", "nutzerprobleme"])) {
    fields.add("Support");
  }
  if (has(["buchhaltung", "rechnung", "zahlung", "finanz", "office", "verwaltung", "dokument", "provision", "compliance"])) {
    fields.add("Buchhaltung/Compliance");
  }
  if (has(["plattform", "api", "release", "openai", "vercel", "canva", "heygen", "github", "app", "mvp"])) {
    fields.add("Plattform-Änderungen");
  }
  if (has(["datenschutz", "recht", "compliance", "risiko", "kundendaten", "personenbezogen", "health", "claim", "medizin", "vertrag"])) {
    fields.add("Datenschutzrisiken");
  }
  if (has(["chance", "projekt", "produkt", "umsatz", "partner", "wachstum", "unternehmenssteuerung", "flowlingo", "health"])) {
    fields.add("Projektchancen");
  }
  if (has(["sprache", "audio", "dialog", "lernen", "lernende", "kurs"])) {
    fields.add("Audio/Sprachfunktionen");
  }
  if (has(["daten", "datenquellen", "feedback", "test", "qualität", "nachweise", "versioniert"])) {
    fields.add("Datenqualität");
  }

  if (fields.size === 0) {
    fields.add("Projektchancen");
    fields.add("Risiken");
  }

  return Array.from(fields);
}

