function renderProductionReadinessCheck() {
  const output = byId("production-readiness-output");
  const overview = getProductionReadinessOverview();
  const activeGroups = overview.groups.filter((group) => group.projects.length > 0);

  output.innerHTML = `
    ${
      overview.projects.length > 0
        ? `
          <article class="decision-overview-item production-readiness-summary">
            <div class="decision-overview-top">
              <span class="status-pill pending">Lageanzeige</span>
              <span class="status-pill pending">Read-only</span>
            </div>
            <p>Diese Kachel zeigt nur lokal, ob genug Kontext, Grenzen und ein nächster manueller Schritt sichtbar sind, damit Jamal später bewusst einen echten Umsetzungsauftrag formulieren könnte.</p>
          </article>
          <div class="production-readiness-counts">
            ${overview.groups
              .map(
                (group) => `
                  <article class="decision-balance-item">
                    <span>${escapeHtml(group.label)}</span>
                    <strong>${group.projects.length}</strong>
                  </article>
                `,
              )
              .join("")}
          </div>
          <div class="decision-overview-list production-readiness-list">
            ${activeGroups
              .map(
                (group) => `
                  <article class="decision-overview-item production-readiness-group">
                    <div class="decision-overview-top">
                      <span class="status-pill ${group.className}">${escapeHtml(group.label)}</span>
                      <span class="tag">${group.projects.length} Projekte</span>
                    </div>
                    ${group.projects
                      .map(
                        (project) => `
                          <article class="production-readiness-project">
                            <h5>${escapeHtml(project.project)}</h5>
                            <div class="production-readiness-grid">
                              <article class="manual-clarification-point">
                                <span>Vorhandener Kontext</span>
                                <strong>${escapeHtml(project.contextSummary)}</strong>
                              </article>
                              <article class="manual-clarification-point">
                                <span>Klare Grenzen</span>
                                <strong>${escapeHtml(project.boundarySummary)}</strong>
                              </article>
                              <article class="manual-clarification-point">
                                <span>Nächster manueller Schritt</span>
                                <strong>${escapeHtml(project.nextManualStep)}</strong>
                              </article>
                              <article class="manual-clarification-point">
                                <span>Bewusste Entscheidungsebene</span>
                                <strong>${escapeHtml(project.decisionLayer)}</strong>
                              </article>
                            </div>
                            ${
                              project.missingPoints.length > 0
                                ? `<p class="decision-risk-note"><strong>Fehlender Punkt:</strong> ${escapeHtml(project.missingPoints.join(", "))}</p>`
                                : `<p class="decision-risk-note">Projektgrundlage wirkt lokal ausreichend vorbereitet. Jamal muss den echten Auftrag trotzdem selbst auswählen, formulieren und freigeben.</p>`
                            }
                          </article>
                        `,
                      )
                      .join("")}
                  </article>
                `,
              )
              .join("")}
          </div>
        `
        : `<p class="empty-state">Keine Projekte sinnvoll einzuordnen.</p>`
    }
    <p class="form-note">Nur lokale Lageanzeige. Kein Auftrag, keine Ausführung, keine Entscheidung, keine Freigabe.</p>
  `;
}

