function showToast(message) {
  const toast = byId("toast");
  toast.textContent = message;
  toast.classList.add("is-visible");
  window.setTimeout(() => toast.classList.remove("is-visible"), 2400);
}

function openDetailsAncestors(element) {
  let node = element?.parentElement;
  while (node) {
    if (node.tagName === "DETAILS") {
      node.open = true;
    }
    node = node.parentElement;
  }
}

function scrollToDemoAnchor(anchorId) {
  if (!anchorId) return;
  const target = document.getElementById(anchorId);
  if (!target) return;
  openDetailsAncestors(target);
  target.scrollIntoView({ behavior: "smooth", block: "start" });
}

const DEMO_HASH_ANCHOR_VIEWS = {
  "hr-agent-daily-suggestion": "cockpit",
  "v1-work-mode-anchor": "cockpit",
  "v1-finish-plan-anchor": "cockpit",
  "portfolio-work-board-anchor": "cockpit",
  "health-pm-run-anchor": "cockpit",
  "health-start-release-anchor": "cockpit",
  "health-weekly-demo-goal-anchor": "cockpit",
  "agent-work-now-anchor": "cockpit",
  "plugin-leitstand-v1-summary-anchor": "cockpit",
  "daily-work-mode-anchor": "cockpit",
  "v1-completion-summary-anchor": "cockpit",
  "v1-freeze-decision-anchor": "cockpit",
  "demo-final-review-decision-anchor": "cockpit",
  "premium-ui-design-system-anchor": "cockpit",
  "plugin-leitstand-demo-anchor": "cockpit",
  "demo-productive-anchor": "cockpit",
  "agent-plugin-readiness": "cockpit",
};

function handleDemoAnchorFromHash() {
  const anchorId = window.location.hash.replace(/^#/, "");
  const viewName = DEMO_HASH_ANCHOR_VIEWS[anchorId];
  if (!viewName) return;
  switchView(viewName, anchorId);
}

function switchView(viewName, anchorId) {
  document.querySelectorAll(".view").forEach((view) => {
    view.classList.toggle("is-active", view.id === `${viewName}-view`);
  });

  document.querySelectorAll(".nav-item").forEach((item) => {
    item.classList.toggle("is-active", item.dataset.view === viewName);
  });

  const currentView = document.querySelector(`#${viewName}-view`);
  byId("view-title").textContent = currentView?.dataset.title || "Cockpit";

  if (anchorId) {
    requestAnimationFrame(() => scrollToDemoAnchor(anchorId));
  } else {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }
}

function openProjectDetail(projectId) {
  const project = state.projects.find((item) => item.id === projectId);
  if (!project) {
    showToast("Projekt ist lokal nicht mehr vorhanden.");
    return;
  }

  state.selectedDetailId = project.id;
  if (project.source === "manual") {
    state.selectedDraftId = project.id;
  }
  saveState();
  renderProjectDetail(project.id);
  switchView("project-detail");
}

window.openProjectDetailFromButton = (button) => {
  openProjectDetail(button.dataset.openProject);
};

function openProjectFromUrl() {
  const projectId = new URLSearchParams(window.location.search).get("project");
  if (!projectId) return false;

  const project = state.projects.find((item) => item.id === projectId);
  state.selectedDetailId = projectId;
  if (project?.source === "manual") {
    state.selectedDraftId = project.id;
  }
  saveState();
  renderProjectDetail(projectId);
  switchView("project-detail");
  return true;
}

window.addEventListener("hashchange", () => {
  openProjectFromUrl();
  handleDemoAnchorFromHash();
});

function airtableLiveCheckLabel(payload) {
  if (!payload || typeof payload !== "object") return "Fehler beim Verbindungstest";
  if (payload.statusCode === "missing_credentials" || payload.status === "missing_credentials" || payload.connectionTest === "not-configured") {
    return "Zugangsdaten fehlen";
  }
  if (payload.status === "reachable" || payload.status === "read-only-erreichbar" || payload.ok === true) return "Airtable erreichbar";
  if (payload.status === "connection_error" || payload.statusCode === "metadata_failed") return "Airtable nicht erreichbar";
  return "Airtable nicht erreichbar";
}

function airtablePilotStatusExplanation(payload) {
  const missingVariables = Array.isArray(payload?.missingVariables) ? payload.missingVariables : [];
  const configured = payload?.configured || {};

  if (!payload || typeof payload !== "object") {
    return {
      label: "Status nicht abrufbar",
      message: "Airtable konnte lokal noch nicht eingeordnet werden. Bitte lokalen Server prüfen.",
      status: "Status nicht abrufbar",
      meaning: "Die lokale Statusprüfung hat keine verwertbare Antwort geliefert.",
      nextStep: "Lokalen Server prüfen und danach den Verbindungscheck erneut öffnen.",
      boundary: "Noch keine Datenanzeige, keine Schreibrechte, keine Automatisierung.",
      copyText: airtableLocalReadOnlyConnection.copyText,
    };
  }

  if (!configured.hasCompleteSetup || missingVariables.length) {
    return {
      label: "Variablen fehlen",
      message: "Airtable kann lokal noch nicht geprüft werden. Es fehlen lokale Zugangsdaten.",
      status: "Airtable lokal noch nicht verbunden",
      meaning: missingVariables.length
        ? `Folgende lokale Variablen fehlen noch: ${missingVariables.join(", ")}.`
        : "Lokale Zugangsdaten fehlen oder sind noch nicht vollständig.",
      nextStep: "Fehlende Variablen lokal in .env.local eintragen, Server neu starten und danach erneut prüfen.",
      boundary: "Noch keine Datenanzeige, keine Feldwerte, keine echten Feldnamen, keine Tabelleninhalte.",
      copyText: airtableLocalReadOnlyConnection.copyTextWhenMissing,
    };
  }

  return {
    label: "Kann geprüft werden",
    message: "Airtable-Zugangsdaten sind lokal vorhanden. Die Verbindung wurde noch nicht automatisch geprüft.",
    status: "Airtable kann jetzt lokal geprüft werden",
    meaning: "Der nächste Schritt bleibt manuell: Verbindung prüfen. Es werden weiterhin keine Datensätze angezeigt.",
    nextStep: "Button „Airtable Verbindung lokal prüfen“ bewusst ausführen und Ergebnis prüfen.",
    boundary: "Noch keine Datenanzeige, keine Schreibrechte, keine Automatisierung.",
    copyText: airtableLocalReadOnlyConnection.copyText,
  };
}

function airtablePilotStatusMarkup(payload) {
  const result = airtablePilotStatusExplanation(payload);
  return `
    <strong>Status:</strong> ${escapeHtml(result.status)}<br>
    <strong>Erklärung:</strong> ${escapeHtml(result.meaning)}<br>
    <strong>Nächster Schritt:</strong> ${escapeHtml(result.nextStep)}<br>
    <strong>Grenze:</strong> ${escapeHtml(result.boundary)}
  `;
}

function airtableChefStatusMarkup(payload) {
  const chefStatus = payload?.chefStatus || {};
  const status = chefStatus.status || airtableLiveCheckExplanation(payload).status;
  const localReachable = chefStatus.localReachable || "noch nicht geprüft";
  const minimalCheckCompleted = chefStatus.minimalCheckCompleted || "nein";
  const dataDisplay = chefStatus.dataDisplay || "weiterhin gesperrt";
  const nextStep = chefStatus.nextStep || airtableLiveCheckExplanation(payload).nextStep;

  return `
    <div><dt>Status</dt><dd>${escapeHtml(status)}</dd></div>
    <div><dt>Lokal erreichbar</dt><dd>${escapeHtml(localReachable)}</dd></div>
    <div><dt>Minimalprüfung sicher abgeschlossen</dt><dd>${escapeHtml(minimalCheckCompleted)}</dd></div>
    <div><dt>Datenanzeige</dt><dd>${escapeHtml(dataDisplay)}</dd></div>
    <div><dt>Nächster sinnvoller Schritt</dt><dd>${escapeHtml(nextStep)}</dd></div>
  `;
}

async function refreshAirtablePilotStatus() {
  const statusTarget = byId("airtable-live-check-status");
  const messageTarget = byId("airtable-live-check-message");
  const resultTarget = byId("airtable-live-check-result");
  const copyTextTarget = byId("airtable-next-step-copytext");
  const chefStatusTarget = byId("airtable-chef-status-summary");

  try {
    const response = await fetch("/api/airtable/pilot-status", {
      method: "GET",
      headers: { Accept: "application/json" },
      cache: "no-store",
    });
    const result = await response.json();
    const explanation = airtablePilotStatusExplanation(result);
    if (statusTarget) statusTarget.textContent = explanation.label;
    if (messageTarget) messageTarget.textContent = explanation.message;
    if (resultTarget) resultTarget.innerHTML = airtablePilotStatusMarkup(result);
    if (copyTextTarget) copyTextTarget.textContent = explanation.copyText;
    if (chefStatusTarget) chefStatusTarget.innerHTML = airtableChefStatusMarkup(result);
  } catch (_error) {
    const explanation = airtablePilotStatusExplanation(null);
    if (statusTarget) statusTarget.textContent = explanation.label;
    if (messageTarget) messageTarget.textContent = explanation.message;
    if (resultTarget) resultTarget.innerHTML = airtablePilotStatusMarkup(null);
    if (copyTextTarget) copyTextTarget.textContent = explanation.copyText;
    if (chefStatusTarget) chefStatusTarget.innerHTML = airtableChefStatusMarkup(null);
  }
}

function airtableLiveCheckExplanation(payload) {
  const missingVariables = Array.isArray(payload?.missingVariables) ? payload.missingVariables : [];
  const missingText = missingVariables.length ? ` Fehlend: ${missingVariables.join(", ")}.` : "";

  if (payload?.statusCode === "missing_credentials" || payload?.status === "missing_credentials" || payload?.connectionTest === "not-configured") {
    return {
      status: "Zugangsdaten fehlen",
      meaning: `Airtable kann lokal noch nicht geprüft werden, weil Zugangsdaten fehlen.${missingText}`,
      nextStep: "Fehlende Variable lokal in .env.local eintragen, Server neu starten und Airtable Verbindung erneut prüfen.",
      boundary: "Noch keine Datenanzeige, keine Schreibrechte, keine automatische Aktion.",
      copyText: airtableLocalReadOnlyConnection.copyTextWhenMissing,
    };
  }

  if (payload?.statusCode === "metadata_ok" || payload?.status === "reachable" || payload?.status === "read-only-erreichbar" || payload?.ok === true) {
    return {
      status: "Airtable erreichbar",
      meaning: "Airtable ist lokal erreichbar. Die Verbindung wurde geprüft. Es werden weiterhin keine Daten angezeigt.",
      nextStep:
        "Read-only Datenanzeige weiterhin gesperrt lassen und zuerst sichere Anzeigegrenze für ausgewählte Testdaten vorbereiten.",
      boundary: "Noch keine Datenanzeige. Keine Datensätze, keine Feldwerte, keine echten Feldnamen, keine Schreibrechte.",
      copyText: airtableLocalReadOnlyConnection.copyTextWhenReachable,
    };
  }

  if (payload?.status === "ready_for_manual_check") {
    const approvalText = payload?.configured?.hasFirstPreviewApproval
      ? "Manuelle Server-Freigabe ist lokal gesetzt."
      : "Manuelle Server-Freigabe fehlt noch.";
    return {
      status: payload?.configured?.hasFirstPreviewApproval
        ? "Bereit für echte lokale Minimalprüfung"
        : "Manuelle Server-Freigabe fehlt",
      meaning: `Lokale Zugangsdaten wirken vollständig. ${approvalText} Browser-Freigaben werden ignoriert.`,
      nextStep: payload?.configured?.hasFirstPreviewApproval
        ? "Lokale Minimalprüfung freigegeben ausführen und Ergebnis nur sanitisiert lesen."
        : "AIRTABLE_FIRST_READONLY_PREVIEW_APPROVED=true nur lokal in .env.local setzen, wenn Jamal die Prüfung freigibt.",
      boundary: "Keine Airtable-Datenanzeige, keine Feldwerte, keine Feldnamen, keine Record-IDs, keine Tabellenstruktur.",
      copyText: airtableLocalReadOnlyConnection.copyText,
    };
  }

  if (payload?.statusCode === "checking") {
    return {
      status: "Live-Check läuft lokal",
      meaning: "Die Prüfung wurde manuell gestartet. Es werden keine Datensätze, Feldwerte oder Tabelleninhalte angezeigt.",
      nextStep: "Ergebnis abwarten und danach fehlende Angaben ergänzen oder Registerstruktur bestätigen.",
      boundary: "Keine automatische Wiederholung, keine Schreibrechte, keine Datenanzeige.",
      copyText: airtableLocalReadOnlyConnection.copyText,
    };
  }

  if (payload?.statusCode === "metadata_failed" || payload?.status === "connection_error" || payload?.status) {
    return {
      status: "Airtable nicht erreichbar",
      meaning: "Airtable konnte lokal nicht erreicht werden. Bitte prüfe Token, Base-ID, Rechte und Netzwerk.",
      nextStep: "Token, Base-ID, Rechte und Netzwerk lokal prüfen und die Airtable Verbindung erneut prüfen.",
      boundary: "Keine Werte im Browser anzeigen, keine Werte loggen, keine Datensatzanzeige, keine Schreibaktion ausführen.",
      copyText: airtableLocalReadOnlyConnection.copyTextWhenMissing,
    };
  }

  return {
    status: "Live-Check konnte nicht ausgewertet werden",
    meaning: "Die lokale Prüfung hat keine verwertbare Antwort geliefert.",
    nextStep: "Lokalen Server prüfen, neu starten und den Live-Check erneut ausführen.",
    boundary: "Keine automatische Wiederholung, keine externe Aktion, keine Datenanzeige.",
    copyText: airtableLocalReadOnlyConnection.copyText,
  };
}

function airtableLiveCheckResultMarkup(payload) {
  const result = airtableLiveCheckExplanation(payload);
  return `
    <strong>Status:</strong> ${escapeHtml(result.status)}<br>
    <strong>Bedeutung:</strong> ${escapeHtml(result.meaning)}<br>
    <strong>Nächster Schritt:</strong> ${escapeHtml(result.nextStep)}<br>
    <strong>Grenze:</strong> ${escapeHtml(result.boundary)}
  `;
}

function airtableFirstPreviewResultMarkup(payload) {
  if (payload?.status === "sanitized_real_local_check_completed" || payload?.status === "minimal_preview_checked") {
    const presenceText =
      payload.minimalRecordPresence === "one_or_more_records_detected"
        ? "ein minimales Ergebnis wäre grundsätzlich vorhanden"
        : payload.minimalRecordPresence === "unknown"
          ? "Minimalergebnis konnte nur technisch geprüft werden"
          : "kein minimales Ergebnis erkannt";
    return `
      <strong>Status:</strong> echte lokale Minimalprüfung sanitisiert abgeschlossen<br>
      <strong>Lokale Freigabe:</strong> erkannt<br>
      <strong>Airtable:</strong> erreichbar<br>
      <strong>Ergebnis:</strong> ${escapeHtml(payload.message || "Die erste echte lokale Airtable-Minimalprüfung wurde read-only ausgeführt und sanitisiert bestätigt.")}<br>
      <strong>Minimalergebnis:</strong> ${escapeHtml(presenceText)}<br>
      <strong>Sicherheitsgrenze aktiv:</strong> keine Rohdaten, keine Feldwerte, keine Feldnamen, keine Record-IDs, keine Tabellenstruktur.
    `;
  }

  if (payload?.status === "missing_credentials") {
    const missingVariables = Array.isArray(payload.missingVariables) && payload.missingVariables.length
      ? `<br><strong>Fehlt:</strong> ${escapeHtml(payload.missingVariables.join(", "))}`
      : "";
    return `
      <strong>Status:</strong> Zugangsdaten fehlen<br>
      <strong>Erklärung:</strong> ${escapeHtml(payload.message || "Minimalanzeige noch nicht freigegeben oder Zugangsdaten fehlen.")}${missingVariables}<br>
      <strong>Grenze:</strong> Keine freie Datenanzeige, keine Feldwerte, keine echten Feldnamen, keine Record-IDs, keine Tabellenstruktur.
    `;
  }

  if (payload?.status === "manual_approval_required" || payload?.status === "preview_not_approved") {
    const missingVariables = Array.isArray(payload.missingVariables) && payload.missingVariables.length
      ? `<br><strong>Fehlt:</strong> ${escapeHtml(payload.missingVariables.join(", "))}`
      : "";
    return `
      <strong>Status:</strong> Manuelle Freigabe fehlt<br>
      <strong>Erklärung:</strong> ${escapeHtml(payload.message || "Manuelle lokale Freigabe fehlt.")}${missingVariables}<br>
      <strong>Grenze:</strong> Keine freie Datenanzeige, keine Feldwerte, keine echten Feldnamen, keine Record-IDs, keine Tabellenstruktur.
    `;
  }

  return `
    <strong>Status:</strong> Airtable nicht erreichbar<br>
    <strong>Erklärung:</strong> ${escapeHtml(payload?.message || "Airtable ist lokal nicht erreichbar oder hat die read-only Minimalprüfung abgelehnt.")}<br>
    <strong>Sicherheitsgrenze aktiv:</strong> keine Rohdaten, keine Feldwerte, keine Feldnamen, keine Record-IDs, keine Tabellenstruktur.
  `;
}

async function runAirtableFirstPreview(button) {
  const previewTarget = byId("airtable-first-preview-result");
  if (button) button.disabled = true;
  if (previewTarget) {
    previewTarget.innerHTML = `
      <strong>Status:</strong> Minimalanzeige wird lokal geprüft<br>
      <strong>Sicherheitsgrenze aktiv:</strong> keine Rohdaten, keine Feldwerte, keine Feldnamen, keine Record-IDs, keine Tabellenstruktur.
    `;
  }

  try {
    const response = await fetch("/api/airtable/first-readonly-preview", {
      method: "GET",
      headers: { Accept: "application/json" },
      cache: "no-store",
    });
    const result = await response.json();
    if (previewTarget) previewTarget.innerHTML = airtableFirstPreviewResultMarkup(result);
    const chefStatusTarget = byId("airtable-chef-status-summary");
    if (chefStatusTarget) chefStatusTarget.innerHTML = airtableChefStatusMarkup(result);
    showToast(result?.message || "Minimalanzeige lokal geprüft. Keine freie Datenanzeige.");
  } catch (_error) {
    if (previewTarget) previewTarget.innerHTML = airtableFirstPreviewResultMarkup(null);
    showToast("Minimalanzeige nicht verfügbar. Keine Daten angezeigt.");
  } finally {
    if (button) button.disabled = false;
  }
}

